  if (!btn) return;
  var visible = !!show;
  if (visible) {
    btn.removeAttribute("hidden");
    btn.setAttribute("aria-hidden", "false");
  } else {
    btn.setAttribute("hidden", "");
    btn.setAttribute("aria-hidden", "true");
  }
