// public/js/manejo-calculators.mjs
function calcVancoDose(p) {
  var w = Number(p.weightKg);
  var mgKg = Number(p.mgPerKg);
  var totalMg = Math.round(w * mgKg);
  var volumeCc = Math.round(totalMg / 5);
  var copyLine = "Vancomicina " + totalMg + " mg diluir en " + volumeCc + " cc glucosado 5% para 2 h cada 12 h";
  return { totalMg, volumeCc, copyLine };
}
function calcBicHuBalanceada(p) {
  var meq = (24 - Number(p.bicPx)) * Number(p.weightKg) * 0.3 / 8.5;
  var rounded = Math.round(meq);
  var third = Math.round(rounded / 3);
  return {
    meqTotal: rounded,
    thirds: [
      { phase: "bolo", meq: third, note: "Sin diluir" },
      { phase: "4h", meq: third, note: "Diluido balanceada HU" },
      { phase: "24h", meq: third, note: "Infusi\xF3n titular 24 h" }
    ],
    copyLine: "Balanceada HU total ~" + rounded + " mEq (3 tercios: " + third + "/" + third + "/" + third + ")"
  };
}
function calcAlbuminParacentesis(p) {
  var L = Number(p.litersRemoved);
  var grams = Math.round(L * 8);
  var ampoules20pct = Math.ceil(grams / 10);
  return {
    grams,
    ampoules20pct,
    copyLine: grams + " g albumina (~" + ampoules20pct + " amp 20%) tras " + L + " L"
  };
}
function calcHypertonicVolume(p) {
  if (p.useWeightRule && p.weightKg != null) {
    var vol = Math.round(Number(p.weightKg) * 3);
    return { volumeCc: vol, copyLine: "Hipert\xF3nica: pasar " + vol + " cc (3 cc/kg)" };
  }
  return { volumeCc: 100, copyLine: "Hipert\xF3nica: 100 cc SS 0.9% + 3 amp NaCl 17.7% en 20 min" };
}
function calcInsulinUnitsPerHour(p) {
  var u = Number(p.weightKg) * Number(p.unitsPerKgPerHour);
  var rounded = Math.round(u * 10) / 10;
  return {
    unitsPerHour: rounded,
    copyLine: "Insulina regular " + p.unitsPerKgPerHour + " U/kg/h \u2192 " + rounded + " U/h"
  };
}
function calcLevetiracetamLoad(p) {
  var mg = Math.round(Number(p.weightKg) * 60);
  return { totalMg: mg, copyLine: "Levetiracetam " + mg + " mg (60 mg/kg) en 100 cc SS 0.9%" };
}
function calcSedationMgPerHour(p) {
  var w = Number(p.weightKg);
  var drug = String(p.drug || "midazolam").toLowerCase();
  if (drug === "propofol") {
    var minMcgKgMin = 5;
    var maxMcgKgMin = 20;
    var mgMin = Math.round(w * minMcgKgMin * 0.06 * 10) / 10;
    var mgMax = Math.round(w * maxMcgKgMin * 0.06 * 10) / 10;
    return {
      drug,
      mgPerHourMin: mgMin,
      mgPerHourMax: mgMax,
      rangeText: "5\u201320 mcg/kg/min (no diluir; m\xE1x 4 mg/kg/h)",
      copyLine: "Propofol " + minMcgKgMin + "\u2013" + maxMcgKgMin + " mcg/kg/min (~" + mgMin + "\u2013" + mgMax + " mg/h). No diluir. M\xE1x 4 mg/kg/h. Permitir titular."
    };
  }
  if (drug === "dexmed") {
    var minMcgKgH = 0.2;
    var maxMcgKgH = 0.7;
    var dexMin = Math.round(w * minMcgKgH) / 1e3;
    var dexMax = Math.round(w * maxMcgKgH) / 1e3;
    return {
      drug,
      mgPerHourMin: dexMin,
      mgPerHourMax: dexMax,
      rangeText: "0.2\u20130.7 mcg/kg/h (IOT: 0.5 mcg/kg/h)",
      copyLine: "Dexmedetomidina 0.2\u20130.7 mcg/kg/h (~" + dexMin + "\u2013" + dexMax + " mg/h). IOT: 0.5 mcg/kg/h. Permitir titular."
    };
  }
  var minMgKgH = 0.02;
  var maxMgKgH = 0.1;
  var mgPerHourMin = Math.round(w * minMgKgH * 100) / 100;
  var mgPerHourMax = Math.round(w * maxMgKgH * 100) / 100;
  return {
    drug: "midazolam",
    mgPerHourMin,
    mgPerHourMax,
    rangeText: "0.02\u20130.1 mg/kg/h (50 mg en 100 cc SS0.9%)",
    copyLine: "Midazolam " + mgPerHourMin + "\u2013" + mgPerHourMax + " mg/h (0.02\u20130.1 mg/kg/h). 50 mg en 100 cc SS0.9%. Permitir titular."
  };
}
var MANEJO_CALCULATORS = {
  "vanco-load": (inputs) => calcVancoDose({ ...inputs, mgPerKg: inputs.mgPerKg ?? 25 }),
  "vanco-maint": (inputs) => calcVancoDose({ ...inputs, mgPerKg: inputs.mgPerKg ?? 17.5 }),
  "bic-hu-balanceada": calcBicHuBalanceada,
  "albumin-paracentesis": calcAlbuminParacentesis,
  "hypertonic-volume": calcHypertonicVolume,
  "insulin-u-kg-h": calcInsulinUnitsPerHour,
  "sedation-mg-kg-h": calcSedationMgPerHour,
  "levetiracetam-load": calcLevetiracetamLoad
};

