// public/js/manejo-dose-units.mjs
var STORAGE_KEY2 = "manejo-dose-unit-mode";
function getDoseUnitMode() {
  try {
    var v = sessionStorage.getItem(STORAGE_KEY2);
    if (v === "standard" || v === "hu") return v;
  } catch (_e) {
  }
  return "hu";
}
function setDoseUnitMode(mode) {
  try {
    sessionStorage.setItem(STORAGE_KEY2, mode === "standard" ? "standard" : "hu");
  } catch (_e) {
  }
}
function calcMcgMinFromPerKg(weightKg, mcgKgMinLow, mcgKgMinHigh) {
  var w = Number(weightKg);
  var lo = Number(mcgKgMinLow);
  var hi = mcgKgMinHigh != null ? Number(mcgKgMinHigh) : lo;
  if (!Number.isFinite(w) || w <= 0 || !Number.isFinite(lo)) {
    return { copyLine: "", mcgMinLow: null, mcgMinHigh: null };
  }
  var mcgMinLow = Math.round(w * lo * 100) / 100;
  var mcgMinHigh = Math.round(w * hi * 100) / 100;
  var range = mcgMinLow === mcgMinHigh ? String(mcgMinLow) : mcgMinLow + "\u2013" + mcgMinHigh;
  return {
    mcgMinLow,
    mcgMinHigh,
    copyLine: "\u2248 " + range + " mcg/min (" + lo + (hi !== lo ? "\u2013" + hi : "") + " mcg/kg/min \xD7 " + w + " kg)"
  };
}
function resolveProtocolWithDoseMode(entry2, mode, weightKg) {
  if (!entry2 || !entry2.doseUnitSwitch) return entry2;
  var sw = entry2.doseUnitSwitch;
  var variant = mode === "standard" ? sw.standard : sw.hu;
  if (!variant) return entry2;
  var resolved = Object.assign({}, entry2);
  if (variant.indicationText) resolved.indicationText = variant.indicationText;
  if (variant.copyTemplate) resolved.copyTemplate = variant.copyTemplate;
  if (variant.someFields) {
    resolved.someFields = Object.assign({}, entry2.someFields || {}, variant.someFields);
  }
  if (variant.notes) resolved.notes = variant.notes.slice();
  if (mode === "standard" && sw.perKgRange && weightKg != null && Number(weightKg) > 0) {
    var conv = calcMcgMinFromPerKg(weightKg, sw.perKgRange[0], sw.perKgRange[1]);
    if (conv.copyLine) {
      resolved.notes = (resolved.notes || []).concat([conv.copyLine]);
    }
  }
  return resolved;
}

