function initProductivityKeyboardShortcuts() {
  document.addEventListener("keydown", function(e) {
    if (e.key === "F6") {
      e.preventDefault();
      toggleFocusMode();
      return;
    }
    if (isPaseMode() && document.body && !document.body.classList.contains("focus-mode")) {
      if (!isTypingContext(e.target) && !e.metaKey && !e.ctrlKey && !e.altKey) {
        var roundKey = (e.key || "").toLowerCase();
        if (roundKey === "j" || roundKey === "k") {
          e.preventDefault();
          rt26.advanceRondaPatient(roundKey === "j" ? 1 : -1);
          return;
        }
      }
    }
    var mod = e.metaKey || e.ctrlKey;
    if (!mod) return;
    if (e.altKey || e.shiftKey) return;
    var k = (e.key || "").toLowerCase();
    if (k === "k") {
      e.preventDefault();
      var bd2 = document.getElementById("unified-search-backdrop");
      if (bd2 && bd2.classList.contains("open")) closeUnifiedSearch();
      else openUnifiedSearch();
    } else if (k === "n") {
      e.preventDefault();
      rt26.openAddModal();
    } else if (k === "s") {
      e.preventDefault();
      if (!rt26.getActiveId()) {
        rt26.showToast("Selecciona un paciente primero", "error");
        return;
      }
      rt26.saveState();
      rt26.addAuditEntry("quick-save", "ok", 1, String(rt26.getActiveId()));
      rt26.showToast("Estado guardado \u2713", "success");
    }
  });
  applyFocusModeFromStorage();
  refreshUndoButtonState();
}
